def sankey_pipeline_diagram(is_retail=True):
    if is_retail:
        stages = ["Intake", "KYC", "Income", "Bureau", "Property", "Decision", "Sanction", "Docs", "Disbursement"]
        counts = [1200, 1050, 920, 850, 720, 680, 620, 590, 550]
    else:
        stages = ["Intake", "KYC", "Financial", "Bureau", "Collateral", "Underwriting", "Sanction", "Docs", "Disbursement"]
        counts = [800, 720, 650, 590, 540, 500, 460, 430, 400]

    fig = go.Figure(data=[go.Sankey(
        node=dict(pad=15, thickness=20, line=dict(color="black", width=0.5), label=stages, color=["#636EFA"]*len(stages)),
        link=dict(source=list(range(len(stages)-1)), target=list(range(1, len(stages))), value=counts[1:],
                  color=[f"rgba(99,110,250,{v/max(counts[1:]):.2f})" for v in counts[1:]])
    )])

    fig.update_layout(title_text=f"{'Retail' if is_retail else 'SME'} Pipeline Flow", font_size=12, height=500, margin=dict(l=20,r=20,t=80,b=20))
    return ft.PlotlyChart(fig, expand=True)

def foir_dscr_gauge(value: float, title: str = "FOIR", max_value: float = 60):
    fig = go.Figure(go.Indicator(mode="gauge+number", value=value, domain={'x': [0, 1], 'y': [0, 1]}, title={'text': title},
                                 gauge={'axis': {'range': [0, max_value * 1.2]}, 'bar': {'color': "darkblue"},
                                        'steps': [{'range': [0, max_value * 0.7], 'color': "lightgreen"},
                                                  {'range': [max_value * 0.7, max_value], 'color': "orange"},
                                                  {'range': [max_value, max_value * 1.2], 'color': "red"}],
                                        'threshold': {'line': {'color': "red", 'width': 4}, 'thickness': 0.75, 'value': max_value}}))
    fig.update_layout(height=300, margin=dict(l=20,r=20,t=50,b=20))
    return ft.PlotlyChart(fig, expand=True)

def radar_scorecard(result, is_retail=True):
    if is_retail:
        metrics = ["CIBIL", "FOIR", "Lead", "Income"]
        values = [result.get("cibil_score",700)/9, 100-result.get("foir_post_loan",40), result.get("lead_score",70), random.uniform(60,90)]
    else:
        metrics = ["CIBIL", "DSCR", "Vintage", "Health"]
        values = [result.get("promoter_cibil_score",700)/9, result.get("dscr",1.4)*30, result.get("vintage",7)*5, result.get("financial_health_score",70)]
    fig = go.Figure(go.Scatterpolar(r=values, theta=metrics, fill='toself'))
    fig.update_layout(polar=dict(radialaxis=dict(range=[0,100])), showlegend=False, height=350)
    return ft.PlotlyChart(fig, expand=True)

def rejection_reasons_chart():
    df = pd.DataFrame({"Reason": ["Low CIBIL","High FOIR","LTV","Vintage","Fraud","Other"], "Count": [320,180,140,90,60,45]})
    pie = px.pie(df, values="Count", names="Reason", title="Rejection Reasons", hole=0.4)
    treemap = px.treemap(df, path=["Reason"], values="Count", title="Rejection Treemap")
    pie.update_layout(height=350); treemap.update_layout(height=350)
    return ft.Column([ft.PlotlyChart(pie), ft.PlotlyChart(treemap)], spacing=10)

def portfolio_treemap(by="city"):
    if by == "city":
        df = pd.DataFrame({"City": ["Bengaluru","Mumbai","Delhi","Hyderabad","Others"], "Amount": [145,92,78,65,220]})
        fig = px.treemap(df, path=["City"], values="Amount", title="Portfolio by City")
    else:
        df = pd.DataFrame({"Industry": ["IT","Manufacturing","Retail","Others"], "Amount": [180,135,98,187]})
        fig = px.treemap(df, path=["Industry"], values="Amount", title="Portfolio by Industry")
    fig.update_layout(height=400)
    return ft.PlotlyChart(fig, expand=True)

def dpd_trend_chart():
    df = pd.DataFrame({
        "Month": ["Jan","Feb","Mar","Apr","May","Jun"],
        "0-30": [620,580,550,520,490,460],
        "31-60": [140,130,120,110,100,90],
        "61-90": [60,55,50,45,40,35],
        "90+": [30,28,25,22,20,18]
    })
    df_melt = df.melt(id_vars="Month", var_name="Bucket", value_name="Count")
    fig = px.area(df_melt, x="Month", y="Count", color="Bucket", title="DPD Trend")
    fig.update_layout(height=400)
    return ft.PlotlyChart(fig, expand=True)

