def main(page: ft.Page):
    page.title = "Loan Processing Dashboard – Retail & SME"
    page.theme_mode = ft.ThemeMode.DARK
    page.padding = 20
    page.bgcolor = ft.colors.with_opacity(0.96, ft.colors.BLUE_GREY_900)

    picked_file = [None]
    current_result = [None, None]  # [result, is_retail]

    file_picker = ft.FilePicker(on_result=lambda e: setattr(picked_file, 0, e.files[0].path) if e.files else None)
    page.overlay.append(file_picker)

    def pick_wav(_): file_picker.pick_files(allowed_extensions=["wav"])

    def start_recording(_):
        page.run_js("""
            let chunks = [];
            navigator.mediaDevices.getUserMedia({audio:true}).then(stream => {
                let recorder = new MediaRecorder(stream);
                recorder.ondataavailable = e => chunks.push(e.data);
                recorder.onstop = () => {
                    let blob = new Blob(chunks, {type:'audio/wav'});
                    let url = URL.createObjectURL(blob);
                    let a = document.createElement('a');
                    a.href = url; a.download = 'recorded_input.wav'; a.click();
                    window.dispatchEvent(new CustomEvent('recordDone', {detail: 'recorded_input.wav'}));
                };
                recorder.start();
                setTimeout(() => recorder.stop(), 8000);
            }).catch(err => alert('Mic error'));
        """)

    def on_record_done(e):
        picked_file[0] = "recorded_input.wav"
        page.show_snack_bar(ft.SnackBar(ft.Text("Recording saved")))

    page.on_event("recordDone", on_record_done)

    def run_stt(target):
        if picked_file[0]:
            text = stt_from_file(picked_file[0])
            target.current.value = text
            page.update()

    def translate_dashboard(_):
        text = "\n".join([str(c.value or "") for c in results_content.controls if hasattr(c, "value")])
        hindi = translate_to_hindi(text)
        results_content.controls.append(ft.Text(f"हिंदी:\n{hindi}", color=ft.colors.YELLOW_300))
        page.update()

    def export_all_charts(_):
        page.show_snack_bar(ft.SnackBar(ft.Text("Exporting charts as PNG/PDF... (mock - add real logic)")))

    # Side panel
    side_panel = ft.Container(visible=False, width=380, bgcolor=ft.colors.with_opacity(0.92, ft.colors.BLUE_GREY_800), padding=16, border_radius=12)

    def show_side_panel(applicant, is_retail=True):
        side_panel.content.controls.clear()
        title = f"{'Retail' if is_retail else 'SME'} Applicant Details"
        details = []
        for k, v in applicant.items():
            if k not in ["id", "created"]:
                details.append(f"{k.replace('_',' ').title()}: {v}")
        side_panel.content.controls.extend([
            ft.Text(title, size=18, weight="bold"),
            ft.Divider(),
            *[ft.Text(d, size=13) for d in details],
            ft.ElevatedButton("Close", on_click=lambda _: setattr(side_panel, "visible", False))
        ])
        side_panel.visible = True
        page.update()

    # ── Retail Form ──────────────────────────────────────────────────
    retail_search = ft.Ref[ft.TextField]()
    retail_dd = ft.Ref[ft.Dropdown]()
    retail_name = ft.Ref[ft.TextField]()

    def update_retail_dropdown(e):
        query = retail_search.current.value.lower() if retail_search.current.value else ""
        filtered = [
            app for app in retail_samples
            if query in app.get("city", "").lower()
            or query in app.get("employment_type", "").lower()
            or query in app.get("name", "").lower()
            or query in app.get("type", "").lower()
            or query in app.get("loan_purpose", "").lower()
        ]
        retail_dd.current.options = [
            ft.dropdown.Option(
                key=app["id"],
                text=f"{app['name']} | {app['city']} | {app['type']} | ₹{app['loan_amt']:,} | {app.get('employment_type','Salaried')} | {app.get('loan_purpose','Personal')}"
            ) for app in filtered[:300]
        ]
        page.update()

    def on_retail_select(e):
        if not retail_dd.current.value:
            side_panel.visible = False
            page.update()
            return
        app = next(a for a in retail_samples if a["id"] == retail_dd.current.value)
        show_side_panel(app, is_retail=True)

    def process_retail(e):
        if not retail_dd.current.value:
            status_text.value = "Select applicant"
            status_text.color = ft.colors.RED_400
            page.update()
            return

        app = next(a for a in retail_samples if a["id"] == retail_dd.current.value)
        app = app.copy()
        app["full_name"] = retail_name.current.value or app["name"]

        progress.visible = True
        status_text.value = "Processing Retail..."
        status_text.color = ft.colors.AMBER_300
        results_content.controls.clear()
        page.update()

        result = RetailPipeline().run(app)
        current_result[0] = result
        current_result[1] = True
        create_dashboard(result, is_retail=True)

        progress.visible = False
        status_text.value = "Retail complete"
        status_text.color = ft.colors.GREEN_300
        page.update()

    retail_form = ft.Column(spacing=14, controls=[
        ft.TextField(ref=retail_search, label="Search by city / employment / name / purpose", on_change=update_retail_dropdown, width=520),
        ft.Dropdown(ref=retail_dd, label="Select Retail Applicant", options=[], width=520, on_change=on_retail_select),
        ft.TextField(ref=retail_name, label="Override Name (optional)"),
        ft.Row([ft.ElevatedButton("Process Retail", on_click=process_retail, icon=ft.icons.PLAY_ARROW_ROUNDED, width=300, height=48),
                progress, status_text], alignment="center")
    ])

    # ── SME Form ─────────────────────────────────────────────────────
    sme_search = ft.Ref[ft.TextField]()
    sme_dd = ft.Ref[ft.Dropdown]()
    sme_name = ft.Ref[ft.TextField]()

    def update_sme_dropdown(e):
        query = sme_search.current.value.lower() if sme_search.current.value else ""
        filtered = [
            app for app in sme_samples
            if query in app.get("city", "").lower()
            or query in app.get("industry", "").lower()
            or query in app.get("name", "").lower()
            or query in app.get("type", "").lower()
            or query in app.get("loan_purpose", "").lower()
        ]
        sme_dd.current.options = [
            ft.dropdown.Option(
                key=app["id"],
                text=f"{app['name']} | {app['city']} | {app['industry']} | {app['type']} | ₹{app['loan_amt']:,}"
            ) for app in filtered[:300]
        ]
        page.update()

    def on_sme_select(e):
        if not sme_dd.current.value:
            side_panel.visible = False
            page.update()
            return
        app = next(a for a in sme_samples if a["id"] == sme_dd.current.value)
        show_side_panel(app, is_retail=False)

    def process_sme(e):
        if not sme_dd.current.value:
            status_text.value = "Select applicant"
            status_text.color = ft.colors.RED_400
            page.update()
            return

        app = next(a for a in sme_samples if a["id"] == sme_dd.current.value)
        app = app.copy()
        app["business_name"] = sme_name.current.value or app["name"]

        progress.visible = True
        status_text.value = "Processing SME..."
        status_text.color = ft.colors.AMBER_300
        results_content.controls.clear()
        page.update()

        result = SMEPipeline().run(app)
        current_result[0] = result
        current_result[1] = False
        create_dashboard(result, is_retail=False)

        progress.visible = False
        status_text.value = "SME complete"
        status_text.color = ft.colors.GREEN_300
        page.update()

    sme_form = ft.Column(spacing=14, controls=[
        ft.TextField(ref=sme_search, label="Search by city / industry / name / purpose", on_change=update_sme_dropdown, width=520),
        ft.Dropdown(ref=sme_dd, label="Select SME Applicant", options=[], width=520, on_change=on_sme_select),
        ft.TextField(ref=sme_name, label="Override Business Name (optional)"),
        ft.Row([ft.ElevatedButton("Process SME", on_click=process_sme, icon=ft.icons.PLAY_ARROW_ROUNDED, width=300, height=48),
                progress, status_text], alignment="center")
    ])

    # Dashboard content
    results_content = ft.Column(scroll=ft.ScrollMode.AUTO, spacing=20, expand=True)

    def create_dashboard(result=None, is_retail=True):
        results_content.controls.clear()
        if not result:
            results_content.controls.append(ft.Text("Run a pipeline to see dashboard", size=18))
            page.update()
            return

        def animated_card(content):
            return ft.Card(
                content=ft.Container(content=content, padding=12, animate_opacity=True, opacity=0),
                elevation=2
            )

        sankey = animated_card(sankey_pipeline_diagram(is_retail))
        gauge1 = animated_card(foir_dscr_gauge(result.get("foir_post_loan", 38.2) if is_retail else result.get("dscr", 1.45)))
        gauge2 = animated_card(ltv_gauge(result.get("ltv_ratio", 68)))
        radar = animated_card(radar_scorecard(result, is_retail))
        rejection = animated_card(rejection_reasons_chart())
        treemap_city = animated_card(portfolio_treemap("city"))
        treemap_ind = animated_card(portfolio_treemap("industry"))
        dpd = animated_card(dpd_trend_chart())

        results_content.controls.extend([
            ft.Text("Loan Processing Dashboard", size=24, weight="bold"),
            ft.Row([sankey], alignment="center"),
            ft.Row([gauge1, gauge2], spacing=15, wrap=True),
            ft.Row([radar, treemap_city], spacing=15, wrap=True),
            ft.Row([treemap_ind, dpd], spacing=15, wrap=True),
            ft.ElevatedButton("Export Dashboard (PNG + PDF)", on_click=export_all_charts, icon=ft.icons.DOWNLOAD)
        ])

        page.update()

    # Tabs layout
    tabs = ft.Tabs(
        selected_index=0,
        tabs=[
            ft.Tab(text="Retail Loans", content=retail_form),
            ft.Tab(text="SME Loans", content=sme_form),
            ft.Tab(text="Dashboard", content=results_content),
        ],
        expand=True
    )

    page.add(
        ft.Container(
            content=ft.Column([
                ft.Text("Loan Processing Dashboard", size=28, weight="bold"),
                tabs
            ], spacing=20),
            padding=24,
            expand=True
        )
    )

    page.update()

ft.app(target=main)













